import React from 'react';
import { Helmet } from 'react-helmet-async';

export default function AccountAddressesPage() {
  return (
    <div>
      <Helmet>
        <title>Addresses | Nova Shop</title>
      </Helmet>
      <h2 style={{ fontSize: '1.25rem', marginBottom: '1rem' }}>Saved addresses</h2>
      <p style={{ color: 'var(--gray)', maxWidth: 480 }}>
        No saved addresses yet. Address management can be added when your API supports it (e.g. user address
        collection on the User model).
      </p>
    </div>
  );
}
